class PersistentSegTree:
def __init__(self, values):
self.n = len(values)
self.vals = sorted(set(values)) # coordinate compression
self.idx = {v:i for i,v in enumerate(self.vals)}
self.t = [] # list of nodes (l, r, sum)
self.root = [self._build(0, self.n-1)]
def _new_node(self, l, r, s):
self.t.append([l, r, s])
return len(self.t)-1
def _build(self, lo, hi):
if lo == hi:
return self._new_node(-1, -1, 0)
mid = (lo+hi)//2
left = self._build(lo, mid)
right = self._build(mid+1, hi)
return self._new_node(left, right, 0)
def _update(self, node, lo, hi, pos, delta):
if lo == hi:
return self._new_node(-1, -1, self.t[node][2] + delta)
mid = (lo+hi)//2
if pos <= mid:
left = self._update(self.t[node][0], lo, mid, pos, delta)
right = self.t[node][1]
else:
left = self.t[node][0]
right = self._update(self.t[node][1], mid+1, hi, pos, delta)
return self._new_node(left, right, self.t[left][2] + self.t[right][2])
def update(self, version, value, delta):
pos = self.idx[value]
new_root = self._update(self.root[version], 0, self.n-1, pos, delta)
self.root.append(new_root)
return len(self.root)-1
def _query(self, node, lo, hi, ql, qr):
if ql > hi or qr < lo:
return 0
if ql <= lo and hi <= qr:
return self.t[node][2]
mid = (lo+hi)//2
return self._query(self.t[node][0], lo, mid, ql, qr) + \
self._query(self.t[node][1], mid+1, hi, ql, qr)
def query(self, version, left_val, right_val):
l = self.idx.get(left_val, 0)
r = self.idx.get(right_val, self.n-1)
return self._query(self.root[version], 0, self.n-1, l, r)
